class Solution {
    public int longestPalindrome(String s, String t) {
        int n = s.length(), m = t.length();
        int max = 0;
        // Case 1: palindrome entirely in s
        max = Math.max(max, longestInOne(s));
        // Case 2: palindrome entirely in t
        max = Math.max(max, longestInOne(t));
        // Case 3: palindrome spans s and t
        // Build combined string with sentinel
        String combined = s + "#" + t;
        int len = combined.length();
        int[] p = manacher(combined);
        for (int i = 0; i < len; i++) {
            int l = i - p[i] + 1;
            int r = i + p[i] - 1;
            if (l <= n && r > n) {
                max = Math.max(max, p[i] * 2 - 1);
            }
        }
        return max;
    }

    private int longestInOne(String s) {
        int n = s.length();
        int max = 0;
        boolean[][] dp = new boolean[n][n];
        for (int i = 0; i < n; i++) {
            dp[i][i] = true;
            max = Math.max(max, 1);
        }
        for (int i = 0; i < n - 1; i++) {
            if (s.charAt(i) == s.charAt(i + 1)) {
                dp[i][i + 1] = true;
                max = Math.max(max, 2);
            }
        }
        for (int len = 3; len <= n; len++) {
            for (int i = 0; i + len <= n; i++) {
                int j = i + len - 1;
                if (s.charAt(i) == s.charAt(j) && dp[i + 1][j - 1]) {
                    dp[i][j] = true;
                    max = Math.max(max, len);
                }
            }
        }
        return max;
    }

    private int[] manacher(String s) {
        int n = s.length();
        int[] p = new int[n];
        int c = 0, r = 0;
        for (int i = 1; i < n - 1; i++) {
            int mirror = 2 * c - i;
            if (i < r) {
                p[i] = Math.min(r - i, p[mirror]);
            }
            while (i + p[i] + 1 < n && i - p[i] - 1 >= 0 &&
                   s.charAt(i + p[i] + 1) == s.charAt(i - p[i] - 1)) {
                p[i]++;
            }
            if (i + p[i] > r) {
                c = i;
                r = i + p[i];
            }
        }
        return p;
    }
}
